<?php/** * AquaLuxe Analytics Admin * * @package AquaLuxe */// Exit if accessed directlyif (!defined('ABSPATH')) {    exit;}/** * AquaLuxe_Analytics_Admin Class * * Handles the admin interface for analytics settings */class AquaLuxe_Analytics_Admin {    /**     * Instance of this class.     *     * @var object     */    protected static $instance = null;    /**     * Initialize the class and set its properties.     */    public function __construct() {        $this->define_hooks();    }    /**     * Get the instance of this class.     *     * @return AquaLuxe_Analytics_Admin A single instance of this class.     */    public static function get_instance() {        if (null === self::$instance) {            self::$instance = new self();        }        return self::$instance;    }    /**     * Define the hooks for the admin interface.     *     * @return void     */    private function define_hooks() {        // Register settings        add_action('admin_init', array($this, 'register_settings'));                // Add settings page        add_action('admin_menu', array($this, 'add_settings_page'));                // Add dashboard widgets        add_action('wp_dashboard_setup', array($this, 'add_dashboard_widgets'));                // Add meta boxes to analytics pages        add_action('add_meta_boxes', array($this, 'add_meta_boxes'));                // Add custom columns to WooCommerce orders        add_filter('manage_edit-shop_order_columns', array($this, 'add_order_analytics_column'));        add_action('manage_shop_order_posts_custom_column', array($this, 'render_order_analytics_column'), 10, 2);                // Add custom columns to products        add_filter('manage_edit-product_columns', array($this, 'add_product_analytics_column'));        add_action('manage_product_posts_custom_column', array($this, 'render_product_analytics_column'), 10, 2);                // Add custom columns to users        add_filter('manage_users_columns', array($this, 'add_user_analytics_column'));        add_filter('manage_users_custom_column', array($this, 'render_user_analytics_column'), 10, 3);                // Add custom columns to subscriptions        add_filter('manage_edit-aqualuxe_subscription_columns', array($this, 'add_subscription_analytics_column'));        add_action('manage_aqualuxe_subscription_posts_custom_column', array($this, 'render_subscription_analytics_column'), 10, 2);                // Add admin notices        add_action('admin_notices', array($this, 'display_admin_notices'));                // Add admin bar menu        add_action('admin_bar_menu', array($this, 'add_admin_bar_menu'), 100);                // Add help tabs        add_action('admin_head', array($this, 'add_help_tabs'));                // Add screen options        add_filter('screen_options_show_screen', array($this, 'add_screen_options'), 10, 2);                // Save user preferences        add_action('personal_options_update', array($this, 'save_user_preferences'));        add_action('edit_user_profile_update', array($this, 'save_user_preferences'));                // Add user profile fields        add_action('show_user_profile', array($this, 'add_user_profile_fields'));        add_action('edit_user_profile', array($this, 'add_user_profile_fields'));                // Add AJAX handlers        add_action('wp_ajax_aqualuxe_analytics_save_dashboard_layout', array($this, 'ajax_save_dashboard_layout'));        add_action('wp_ajax_aqualuxe_analytics_export_report', array($this, 'ajax_export_report'));        add_action('wp_ajax_aqualuxe_analytics_save_report_settings', array($this, 'ajax_save_report_settings'));        add_action('wp_ajax_aqualuxe_analytics_dismiss_notice', array($this, 'ajax_dismiss_notice'));    }    /**     * Register settings for analytics.     *     * @return void     */    public function register_settings() {        // Register settings        register_setting(            'aqualuxe_analytics_settings',            'aqualuxe_analytics_settings',            array(                'sanitize_callback' => array($this, 'sanitize_settings'),            )        );                // Add settings sections        add_settings_section(            'aqualuxe_analytics_general_section',            __('General Settings', 'aqualuxe'),            array($this, 'render_general_section'),            'aqualuxe_analytics_settings'        );                add_settings_section(            'aqualuxe_analytics_data_section',            __('Data Collection Settings', 'aqualuxe'),            array($this, 'render_data_section'),            'aqualuxe_analytics_settings'        );                add_settings_section(            'aqualuxe_analytics_display_section',            __('Display Settings', 'aqualuxe'),            array($this, 'render_display_section'),            'aqualuxe_analytics_settings'        );                add_settings_section(            'aqualuxe_analytics_export_section',            __('Export Settings', 'aqualuxe'),            array($this, 'render_export_section'),            'aqualuxe_analytics_settings'        );                // Add settings fields                // General settings        add_settings_field(            'enable_analytics',            __('Enable Analytics', 'aqualuxe'),            array($this, 'render_enable_analytics_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_general_section'        );                add_settings_field(            'user_roles',            __('User Roles', 'aqualuxe'),            array($this, 'render_user_roles_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_general_section'        );                add_settings_field(            'dashboard_widgets',            __('Dashboard Widgets', 'aqualuxe'),            array($this, 'render_dashboard_widgets_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_general_section'        );                // Data collection settings        add_settings_field(            'data_retention',            __('Data Retention', 'aqualuxe'),            array($this, 'render_data_retention_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_data_section'        );                add_settings_field(            'anonymize_data',            __('Anonymize Data', 'aqualuxe'),            array($this, 'render_anonymize_data_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_data_section'        );                add_settings_field(            'track_events',            __('Track Events', 'aqualuxe'),            array($this, 'render_track_events_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_data_section'        );                // Display settings        add_settings_field(            'default_date_range',            __('Default Date Range', 'aqualuxe'),            array($this, 'render_default_date_range_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_display_section'        );                add_settings_field(            'chart_colors',            __('Chart Colors', 'aqualuxe'),            array($this, 'render_chart_colors_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_display_section'        );                add_settings_field(            'currency_format',            __('Currency Format', 'aqualuxe'),            array($this, 'render_currency_format_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_display_section'        );                // Export settings        add_settings_field(            'export_format',            __('Export Format', 'aqualuxe'),            array($this, 'render_export_format_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_export_section'        );                add_settings_field(            'scheduled_reports',            __('Scheduled Reports', 'aqualuxe'),            array($this, 'render_scheduled_reports_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_export_section'        );                add_settings_field(            'report_recipients',            __('Report Recipients', 'aqualuxe'),            array($this, 'render_report_recipients_field'),            'aqualuxe_analytics_settings',            'aqualuxe_analytics_export_section'        );    }}// Initialize the analytics admin classAquaLuxe_Analytics_Admin::get_instance();